commands.examples:
-- Fungsi sederhana
CREATE OR REPLACE FUNCTION add_tax(price DECIMAL, rate DECIMAL DEFAULT 0.11)
RETURNS DECIMAL AS $$
BEGIN
  RETURN price + (price * rate);
END;
$$ LANGUAGE plpgsql IMMUTABLE;

SELECT add_tax(100000); -- 111000

-- Fungsi return TABLE
CREATE FUNCTION get_user_orders(uid INT)
RETURNS TABLE(order_id INT, total DECIMAL, status TEXT) AS $$
BEGIN
  RETURN QUERY SELECT id, total, status FROM orders WHERE user_id = uid;
END;
$$ LANGUAGE plpgsql STABLE;

SELECT * FROM get_user_orders(1);

