commands.examples:
CREATE FUNCTION check_stock(pid INT) RETURNS TEXT AS $$
DECLARE
  qty INT;
BEGIN
  SELECT stock INTO qty FROM products WHERE id = pid;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Product % not found', pid;
  ELSIF qty = 0 THEN
    RETURN 'out_of_stock';
  ELSIF qty < 10 THEN
    RETURN 'low_stock';
  ELSE
    RETURN 'in_stock';
  END IF;
EXCEPTION
  WHEN OTHERS THEN
    RAISE NOTICE 'Error: %', SQLERRM;
    RETURN 'error';
END;
$$ LANGUAGE plpgsql;
